#!/usr/bin/env python3
from pathlib import Path

ROOT = Path.cwd()
required = ["package.json", "app"]
for rel in required:
    if not (ROOT / rel).exists():
        raise FileNotFoundError(f"No encuentro {rel}. Ejecuta este script desde la raíz del proyecto mundial-porra-2026.")

(ROOT / "app/page.tsx").write_text('import { StandingCard } from "@/components/StandingCard";\nimport { formatDateSection, resultLabel } from "@/lib/format";\nimport { getFootballDataResults } from "@/lib/footballData";\nimport { getMatches, getStandings } from "@/lib/scoring";\n\nexport const revalidate = 600;\n\ntype ResultsPayload = Awaited<ReturnType<typeof getFootballDataResults>>;\n\nfunction getLastFinishedMatch(results: ResultsPayload["results"]) {\n  return getMatches()\n    .filter((match) => results[match.id]?.status === "FINISHED")\n    .sort((a, b) => {\n      const dateA = `${a.date ?? ""}-${String(a.id).padStart(3, "0")}`;\n      const dateB = `${b.date ?? ""}-${String(b.id).padStart(3, "0")}`;\n      return dateB.localeCompare(dateA);\n    })[0];\n}\n\nconst podiumMedals = ["🥇", "🥈", "🥉"];\n\nexport default async function HomePage() {\n  const payload = await getFootballDataResults();\n  const standings = getStandings(payload.results);\n  const played = Object.keys(payload.results).length;\n  const total = getMatches().length;\n  const podium = standings.slice(0, 3);\n  const rest = standings.slice(3);\n  const lastMatch = getLastFinishedMatch(payload.results);\n  const lastResult = lastMatch ? payload.results[lastMatch.id] : undefined;\n\n  return (\n    <section className="screen">\n      <header className="page-header">\n        <div className="section-label">🏆 Mundial 2026</div>\n        <h1>Clasificación</h1>\n        <p>{played}/{total} partidos puntuados</p>\n      </header>\n\n      {payload.error ? (\n        <div className="system-notice">Actualizando resultados...</div>\n      ) : null}\n\n      {lastMatch && lastResult ? (\n        <section className="last-result-card">\n          <div>\n            <span className="section-label">Último resultado</span>\n            <h2>{lastMatch.home} - {lastMatch.away}</h2>\n            <p>{formatDateSection(lastMatch.date)}</p>\n          </div>\n          <strong>{resultLabel(lastResult)}</strong>\n        </section>\n      ) : null}\n\n      <section className="block classification-only-block">\n        <div className="podium">\n          {podium.map((row, index) => (\n            <a\n              key={row.player}\n              href={`/pronosticos/${encodeURIComponent(row.player)}`}\n              className={`podium-card rank-${index + 1}`}\n            >\n              <div className="podium-top">{podiumMedals[index]}</div>\n              <div className="podium-name">{row.player}</div>\n              <div className="podium-score">{row.points}</div>\n              <div className="muted">\n                {row.played === 0 ? "Salida" : `${row.correct}/${row.played} · ${row.percentage}%`}\n              </div>\n            </a>\n          ))}\n        </div>\n\n        <div className="standing-list">\n          {rest.map((row, index) => (\n            <StandingCard key={row.player} row={row} position={index + 4} compact />\n          ))}\n        </div>\n      </section>\n    </section>\n  );\n}\n', encoding="utf-8")

css_path = ROOT / "app/globals.css"
css = css_path.read_text(encoding="utf-8")

markers = [
    "/* V8 final design */",
    "/* Compact home polish */",
    "/* Classification-only home */",
    "/* Sports polish: typography, classification and non-technical status */",
    "/* Rescue clean design after V8 rollback */",
    "/* Stable visual baseline */",
    "/* UI consistency pass */",
    "/* Surgical layout fix: width, tabs and consistent pages */",
]

for marker in markers:
    while marker in css:
        start = css.index(marker)
        next_positions = [css.find(m, start + len(marker)) for m in markers if css.find(m, start + len(marker)) != -1]
        end = min(next_positions) if next_positions else len(css)
        css = css[:start].rstrip() + "\n\n" + css[end:].lstrip()

css = css.rstrip() + "\n\n" + '/* Surgical layout fix: width, tabs and consistent pages */\n:root {\n  --app-bg: #fff4d8;\n  --app-card: rgba(255, 255, 255, 0.86);\n  --app-border: rgba(25, 20, 12, 0.11);\n  --app-text: #17130c;\n  --app-muted: #7d705f;\n  --app-accent: #ffb21a;\n  --app-accent-soft: #fff0c2;\n}\n\nhtml,\nbody {\n  background: var(--app-bg);\n  color: var(--app-text);\n  font-family: -apple-system, BlinkMacSystemFont, "SF Pro Text", "Segoe UI", Roboto, Arial, sans-serif;\n}\n\n.screen {\n  width: 100%;\n  max-width: 520px;\n  margin: 0 auto;\n  padding: 18px 14px 112px;\n  box-sizing: border-box;\n}\n\n.page-header,\n.app-header {\n  margin: 0;\n  padding: 8px 0 16px;\n  border: 0;\n  background: transparent;\n  box-shadow: none;\n}\n\n.section-label {\n  color: #946400;\n  font-size: 12px;\n  line-height: 1.2;\n  font-weight: 800;\n  letter-spacing: 0.04em;\n  text-transform: uppercase;\n}\n\n.page-header h1,\n.app-header h1 {\n  margin: 7px 0 0;\n  color: var(--app-text);\n  font-size: clamp(38px, 10vw, 50px);\n  line-height: 0.98;\n  font-weight: 820;\n  letter-spacing: -0.05em;\n}\n\n.page-header p,\n.app-header p {\n  margin: 9px 0 0;\n  color: var(--app-muted);\n  font-size: 18px;\n  line-height: 1.35;\n  font-weight: 650;\n}\n\n.block,\n.quiet-card,\n.match-card,\n.player-row,\n.standing-row,\n.last-result-card {\n  border: 1px solid var(--app-border);\n  background: var(--app-card);\n  box-shadow: 0 10px 28px rgba(58, 42, 13, 0.06);\n}\n\n.block {\n  margin-top: 12px;\n  padding: 10px;\n  border-radius: 24px;\n}\n\n.classification-only-block {\n  margin-top: 12px;\n}\n\n.podium {\n  display: grid;\n  gap: 10px;\n}\n\n.podium-card {\n  min-height: 72px;\n  padding: 10px 12px;\n  border-radius: 22px;\n}\n\n.podium-top {\n  width: 46px;\n  height: 46px;\n  font-size: 21px;\n}\n\n.podium-name,\n.standing-name,\n.player-name,\n.team {\n  color: var(--app-text);\n  font-weight: 800;\n  letter-spacing: -0.03em;\n}\n\n.podium-score {\n  font-weight: 850;\n}\n\n.standing-row {\n  min-height: 68px;\n  padding: 12px;\n  border-radius: 20px;\n}\n\n.standing-position {\n  min-width: 34px;\n}\n\n.standing-points strong {\n  font-size: 30px;\n}\n\n.last-result-card {\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  gap: 14px;\n  margin-top: 2px;\n  padding: 14px 16px;\n  border-radius: 22px;\n}\n\n.last-result-card h2 {\n  margin: 5px 0 3px;\n  color: var(--app-text);\n  font-size: 23px;\n  line-height: 1.05;\n  font-weight: 820;\n  letter-spacing: -0.035em;\n}\n\n.last-result-card p {\n  margin: 0;\n  color: var(--app-muted);\n  font-size: 14px;\n  font-weight: 600;\n}\n\n.last-result-card strong {\n  flex: 0 0 auto;\n  padding: 10px 12px;\n  border-radius: 16px;\n  background: var(--app-text);\n  color: #fff7df;\n  font-size: 21px;\n  line-height: 1;\n  font-weight: 850;\n  letter-spacing: -0.035em;\n}\n\n.block-heading {\n  margin-bottom: 12px;\n}\n\n.block-heading h2,\n.date-title h2,\n.quiet-card h2 {\n  color: var(--app-text);\n  font-size: 30px;\n  line-height: 1.05;\n  font-weight: 820;\n  letter-spacing: -0.04em;\n}\n\n.block-heading span,\n.date-title span,\n.muted {\n  color: var(--app-muted);\n}\n\n.match-card {\n  padding: 16px;\n  border-radius: 24px;\n}\n\n.match-topline {\n  margin-bottom: 18px;\n}\n\n.match-main {\n  margin-bottom: 12px;\n}\n\n.team {\n  font-size: clamp(24px, 6vw, 32px);\n}\n\n.score {\n  min-width: 54px;\n  min-height: 48px;\n}\n\n.match-time {\n  margin-bottom: 14px;\n  font-size: 15px;\n}\n\n.pick-row {\n  gap: 8px;\n}\n\n.pick-button {\n  min-height: 44px;\n  padding: 10px 14px;\n  border-radius: 18px;\n}\n\n.player-list,\n.date-stack {\n  margin-top: 12px;\n}\n\n.date-section {\n  margin-top: 22px;\n}\n\n.date-section:first-child {\n  margin-top: 0;\n}\n\n.system-notice {\n  margin-top: 2px;\n  border: 1px solid rgba(154, 106, 0, 0.18);\n  border-radius: 18px;\n  background: var(--app-accent-soft);\n  color: #8a5b00;\n  font-size: 14px;\n  font-weight: 750;\n}\n\n/* Bottom nav: keep full labels but avoid squeezing */\n.bottom-nav {\n  left: 10px !important;\n  right: 10px !important;\n  width: auto !important;\n  max-width: none !important;\n  display: flex;\n  gap: 2px;\n  padding: 6px;\n  border-top: 1px solid var(--app-border);\n  border-radius: 999px;\n  background: rgba(255, 250, 237, 0.94);\n  box-shadow: 0 10px 34px rgba(50, 35, 9, 0.12);\n  backdrop-filter: blur(18px);\n  box-sizing: border-box;\n}\n\n.bottom-nav a {\n  flex: 1 1 0;\n  min-width: 0;\n  padding: 12px 2px;\n  border-radius: 999px;\n  color: var(--app-muted);\n  font-size: clamp(12px, 3.25vw, 14px);\n  line-height: 1;\n  font-weight: 800;\n  text-align: center;\n  white-space: nowrap;\n  letter-spacing: -0.02em;\n}\n\n.bottom-nav a.active {\n  background: var(--app-accent);\n  color: var(--app-text);\n}\n\n.live-badge,\n.leader-note {\n  display: none !important;\n}\n\n@media (max-width: 390px) {\n  .screen {\n    padding-left: 12px;\n    padding-right: 12px;\n  }\n\n  .page-header h1,\n  .app-header h1 {\n    font-size: 38px;\n  }\n\n  .page-header p,\n  .app-header p {\n    font-size: 16px;\n  }\n\n  .bottom-nav {\n    left: 8px !important;\n    right: 8px !important;\n  }\n\n  .bottom-nav a {\n    font-size: 12px;\n  }\n}\n' + "\n"
css_path.write_text(css, encoding="utf-8")

print("Aplicado arreglo quirúrgico de layout:")
print("- Menos margen lateral en todas las pestañas.")
print("- Barra inferior menos apretada.")
print("- Títulos y tarjetas homogeneizados.")
print("- Home mantiene solo clasificación y último resultado cuando exista.")
print("- Eliminados textos redundantes.")
print("")
print("Ejecuta:")
print("npm run build")
print("git add .")
print("git commit -m 'Fix layout width and navigation'")
print("git push")
print("npx vercel --prod")
